function minMaxStack(operations, values) {
  const stack = [];
  const minMaxS = [];
  const results = [];
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const args = values[i];
    if (op === 'MinMaxStack') {
      results.push(null);
      continue;
    }
    if (op === 'push') {
      const val = args[0];
      stack.push(val);
      const prev = minMaxS.length > 0 ? minMaxS[minMaxS.length - 1] : null;
      minMaxS.push({
        min: prev === null ? val : Math.min(val, prev.min),
        max: prev === null ? val : Math.max(val, prev.max)
      });
      results.push(null);
      continue;
    }
    if (op === 'pop') {
      stack.pop();
      minMaxS.pop();
      results.push(null);
      continue;
    }
    if (op === 'top') {
      results.push(stack[stack.length - 1]);
      continue;
    }
    if (op === 'getMin') {
      results.push(minMaxS[minMaxS.length - 1].min);
      continue;
    }
    if (op === 'getMax') {
      results.push(minMaxS[minMaxS.length - 1].max);
      continue;
    }
  }
  return results;
}
